@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="dropZoneElement" class="file-drop-zone @(isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (files.Count > 0)
{
    <ul class="file-drop-zone-list">
        @foreach (var entry in files)
        {
            <li class="file-drop-zone-item @(entry.Error is not null ? "file-error" : "")">
                @if (entry.Error is not null)
                {
                    <span class="file-error-message">@entry.Info.Name &mdash; @entry.Error</span>
                }
                else
                {
                    <span class="file-info">@entry.Info.Name (@FormatSize(entry.Info.Size)) &mdash; @entry.Info.Type</span>
                }
                <button class="btn btn-sm btn-danger" @onclick="() => Remove(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10 * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference dropZoneElement;
    private IJSObjectReference? jsModule;
    private bool isDragOver;
    private List<FileEntry> files = new();

    private record FileEntry(FileInfo Info, string? Error);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>("import", "./Components/FileDropZone.razor.js");
            await jsModule.InvokeVoidAsync("initDropZone", dropZoneElement, DotNetObjectReference.Create(this));
        }
    }

    [JSInvokable]
    public void OnDragOverChanged(bool over)
    {
        isDragOver = over;
        StateHasChanged();
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileDropData[] droppedFiles)
    {
        isDragOver = false;

        foreach (var f in droppedFiles)
        {
            var info = new FileInfo(f.Name, f.Size, f.Type);
            string? error = f.Size > MaxFileSize ? $"File exceeds 10 MB limit ({FormatSize(f.Size)})" : null;
            files.Add(new FileEntry(info, error));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task Remove(FileEntry entry)
    {
        files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = files.Where(f => f.Error is null).Select(f => f.Info).ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes)
    {
        if (bytes < 1024) return $"{bytes} B";
        if (bytes < 1024 * 1024) return $"{bytes / 1024.0:F1} KB";
        return $"{bytes / (1024.0 * 1024.0):F1} MB";
    }

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("dispose", dropZoneElement);
            await jsModule.DisposeAsync();
        }
    }

    public record struct FileDropData(string Name, long Size, string Type);
}

const instances = new Map();

export function initDropZone(element, dotNetRef) {
    function onDragOver(e) {
        e.preventDefault();
        dotNetRef.invokeMethodAsync('OnDragOverChanged', true);
    }

    function onDragLeave(e) {
        e.preventDefault();
        dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
    }

    function onDrop(e) {
        e.preventDefault();
        const files = [];
        for (const file of e.dataTransfer.files) {
            files.push({ name: file.name, size: file.size, type: file.type || 'application/octet-stream' });
        }
        dotNetRef.invokeMethodAsync('OnFilesDropped', files);
    }

    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    instances.set(element, { onDragOver, onDragLeave, onDrop });
}

export function dispose(element) {
    const handlers = instances.get(element);
    if (handlers) {
        element.removeEventListener('dragover', handlers.onDragOver);
        element.removeEventListener('dragleave', handlers.onDragLeave);
        element.removeEventListener('drop', handlers.onDrop);
        instances.delete(element);
    }
}

.file-drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    text-align: center;
    color: #6c757d;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.file-drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: rgba(13, 110, 253, 0.05);
    color: #0d6efd;
}

.file-drop-zone-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-drop-zone-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-drop-zone-item.file-error {
    border-color: #dc3545;
    background-color: rgba(220, 53, 69, 0.05);
}

.file-error-message {
    color: #dc3545;
    font-weight: 500;
}

